server {
    listen 8080;
    server_name localhost;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log custom;
    error_log /var/log/nginx/benchmark-error.log;

    limit_req zone=one burst=10;

    location / {
        try_files $uri $uri/ =404;
    }

    error_page 404 /404.html;
    location = /404.html {
        root /var/www/html;
        internal;
    }
}

